        #region 状态机
        private class LockedChestStateMachine : EntityStateMachine
        {
            public LockedChestStateMachine()
            {
                AddState(new IdleState());
                AddState(new JumpState());
                AddState(new ChargeState());
                AddState(new SpitTrashState());
                AddState(new SpitZombieBlueprintState());
                AddState(new StunnedState());
                AddState(new DeathState());
            }
        }
        #endregion

        #region 待命
        private static bool CanSwitchStatePhase1(Entity entity, int state)
        {
            switch (state)
            {
            }
            return true;
        }
        private static bool CanSwitchStatePhase2(Entity entity, int state)
        {
            switch (state)
            {
            }
            return true;
        }
        private static void SwitchState(Entity entity, int state)
        {
            switch (state)
            {
                default:
                    {
                        stateMachine.StartState(entity, state);
                    }
                    break;
            }
        }
        private class IdleState : EntityStateMachineState
        {
            public IdleState() : base(STATE_IDLE, ANIMATION_STATE_IDLE) { }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var stateTimer = stateMachine.GetStateTimer(entity);
                stateTimer.ResetSeconds(0.5f);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                UpdateStateSwitch(stateMachine, entity);
            }
            private void UpdateStateSwitch(EntityStateMachine stateMachine, Entity entity)
            {
                var stateTimer = stateMachine.GetStateTimer(entity);
                stateTimer.Run(stateMachine.GetSpeed(entity));
                if (stateTimer.Expired)
                {
                    var nextIndex = stateMachine.GetNextStateIndex(entity);
                    int[] pool;
                    if (GetPhase(entity) == PHASE_1)
                    {
                        pool = statePoolPhase1;
                        nextIndex = pool.FindNextStateIndex(nextIndex, state => CanSwitchStatePhase1(entity, state));
                    }
                    else
                    {
                        pool = statePoolPhase2;
                        nextIndex = pool.FindNextStateIndex(nextIndex, state => CanSwitchStatePhase2(entity, state));
                    }
                    if (nextIndex >= 0)
                    {
                        var state = pool[nextIndex];
                        stateMachine.SetNextStateIndex(entity, nextIndex + 1);
                        SwitchState(entity, state);
                    }
                    else
                    {
                        stateTimer.Reset();
                    }
                }
            }
        }
        #endregion

        #region 跳跃
        private static Vector2Int GetNewJumpTargetGridOffset(Entity entity)
        {
            var column = entity.GetColumn();
            var lane = entity.GetLane();
            var maxLane = entity.Level.GetMaxLaneCount();
            var directionX = entity.GetFacingX();
            if (column <= 1)
            {
                directionX = 1;
            }
            else if (column >= entity.Level.GetMaxColumnCount() - 2)
            {
                directionX = -1;
            }
            var possibleLaneOffsets = new List<int>();
            for (int side = 0; side < 2; side++)
            {
                var directionY = side * 2 - 1;
                for (int length = 1; length <= 2; length++)
                {
                    var laneOffset = directionY * length;
                    var targetLane = lane + laneOffset;
                    if (targetLane >= 0 && targetLane < maxLane)
                    {
                        possibleLaneOffsets.Add(laneOffset);
                    }
                }
            }
            var resultLaneOffset = 0;
            if (possibleLaneOffsets.Count > 0)
            {
                resultLaneOffset = possibleLaneOffsets.Random(entity.RNG);
            }
            return new Vector2Int(directionX * (3 - Mathf.Abs(resultLaneOffset)), resultLaneOffset);
        }
        private static Vector3 GetNewJumpTarget(Entity entity)
        {
            var offset = GetNewJumpTargetGridOffset(entity);
            return entity.Level.GetEntityGridPosition(entity.GetColumn() + offset.x, entity.GetLane() + offset.y);
        }
        private static void StartJump(Entity boss, float inAirSeconds, Vector3 targetPosition)
        {
            var inAirTicks = Ticks.FromSeconds(inAirSeconds);
            Vector3 velocity = VanillaProjectileExt.GetLobVelocityByTime(boss.Position, targetPosition, inAirTicks, boss.GetGravity());
            boss.Velocity = velocity;
            SetFlipX(boss, targetPosition.x > boss.Position.x);
        }
        private class JumpState : EntityStateMachineState
        {
            public JumpState() : base(STATE_JUMP, ANIMATION_STATE_JUMP) { }
            public override int GetAnimationSubstate(int substate)
            {
                if (substate == SUBSTATE_END)
                {
                    return ANIMATION_SUBSTATE_LAND;
                }
                return ANIMATION_SUBSTATE_JUMP;
            }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                StartJump(entity, jumpFlyingSeconds, GetNewJumpTarget(entity));
            }
            public override void OnExit(EntityStateMachine machine, Entity entity)
            {
                base.OnExit(machine, entity);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_START:
                        if (entity.IsOnGround)
                        {
                            entity.PlaySound(VanillaSoundID.wood);
                            stateMachine.StartSubState(entity, SUBSTATE_END);
                            timer.ResetSeconds(1 / 6f);
                        }
                        break;
                    case SUBSTATE_END:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public const int SUBSTATE_START = 0;
            public const int SUBSTATE_END = 1;
            public const int ANIMATION_SUBSTATE_JUMP = 0;
            public const int ANIMATION_SUBSTATE_LAND = 1;

            public const float jumpFlyingSeconds = 0.5f;
        }
        #endregion

        #region 冲刺
        private static Vector3 GetNewChargeTarget(Entity entity)
        {
            var offset = GetNewJumpTargetGridOffset(entity);
            offset.x += Math.Sign(offset.x) * 3;
            return entity.Level.GetEntityGridPosition(entity.GetColumn() + offset.x, entity.GetLane() + offset.y);
        }
        private static int GetShadowVariant(Entity entity, bool smash)
        {
            int variant = 0;
            if (GetPhase(entity) == PHASE_2)
            {
                variant |= 1;
            }
            if (smash)
            {
                variant |= 2;
            }
            return variant;
        }
        private static void SpawnShadow(Entity entity, bool smash = false)
        {
            var param = entity.GetSpawnParams();
            param.SetProperty(EngineEntityProps.DISPLAY_SCALE, entity.GetDisplayScale());
            param.SetProperty(EngineEntityProps.FLIP_X, entity.IsFlipX());
            param.SetProperty(LogicEntityProps.VARIANT, GetShadowVariant(entity, smash));
            entity.Spawn(VanillaEffectID.lockedChestShadow, entity.Position, param);
        }
        private static void ChargeCrush(Entity entity)
        {
            var level = entity.Level;
            crushBuffer.Clear();
            crushDetector.DetectMultiple(entity, crushBuffer);
            foreach (IEntityCollider collider in crushBuffer)
            {
                var ent = collider.Entity;
                var damageOutput = collider.TakeDamage(300, new DamageEffectList(VanillaDamageEffects.IMPACT, VanillaDamageEffects.IGNORE_ARMOR), entity);
                if (ent.Type == EntityTypes.PLANT)
                {
                    if (damageOutput?.BodyResult?.Fatal ?? false)
                    {
                        entity.PlaySound(VanillaSoundID.smash);
                    }
                }
            }
        }
        private class ChargeState : EntityStateMachineState
        {
            public ChargeState() : base(STATE_CHARGE, ANIMATION_STATE_JUMP) { }
            public override int GetAnimationState(int substate)
            {
                if (substate == SUBSTATE_SHAKE)
                {
                    return ANIMATION_STATE_IDLE;
                }
                return base.GetAnimationState(substate);
            }
            public override int GetAnimationSubstate(int substate)
            {
                if (substate == SUBSTATE_END)
                {
                    return ANIMATION_SUBSTATE_LAND;
                }
                return ANIMATION_SUBSTATE_JUMP;
            }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.ResetSeconds(1);
                entity.SetAnimationBool("Shake", true);
            }
            public override void OnExit(EntityStateMachine machine, Entity entity)
            {
                base.OnExit(machine, entity);
                entity.SetAnimationBool("Shake", false);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_SHAKE:
                        if (timer.Expired)
                        {
                            StartJump(entity, jumpFlyingSeconds, GetNewChargeTarget(entity));
                            stateMachine.StartSubState(entity, SUBSTATE_CHARGE1);
                            entity.SetAnimationBool("Shake", false);
                        }
                        break;
                    case SUBSTATE_CHARGE1:
                    case SUBSTATE_CHARGE2:
                        {
                            SpawnShadow(entity);
                            if (entity.IsOnGround)
                            {
                                entity.PlaySound(VanillaSoundID.wood);
                                StartJump(entity, jumpFlyingSeconds, GetNewChargeTarget(entity));
                                ChargeCrush(entity);
                                stateMachine.StartSubState(entity, substate + 1);
                            }
                        }
                        break;
                    case SUBSTATE_CHARGE3:
                        {
                            SpawnShadow(entity);
                            if (entity.IsOnGround)
                            {
                                entity.PlaySound(VanillaSoundID.wood);
                                ChargeCrush(entity);
                                stateMachine.StartSubState(entity, SUBSTATE_END);
                                timer.ResetSeconds(1 / 6f);
                            }
                        }
                        break;
                    case SUBSTATE_END:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            public const int SUBSTATE_SHAKE = 0;
            public const int SUBSTATE_CHARGE1 = 1;
            public const int SUBSTATE_CHARGE2 = 2;
            public const int SUBSTATE_CHARGE3 = 3;
            public const int SUBSTATE_END = 4;

            public const int ANIMATION_SUBSTATE_JUMP = 0;
            public const int ANIMATION_SUBSTATE_LAND = 1;

            public const float jumpFlyingSeconds = 0.5f;
        }
        #endregion

        #region 吐垃圾
        private class SpitTrashState : EntityStateMachineState
        {
            public SpitTrashState() : base(STATE_SPIT_TRASH, ANIMATION_STATE_OPEN_CHEST) { }
            public override int GetAnimationSubstate(int substate)
            {
                if (substate == SUBSTATE_END)
                {
                    return ANIMATION_SUBSTATE_CLOSE;
                }
                return ANIMATION_SUBSTATE_OPEN;
            }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var substateTimer = stateMachine.GetSubStateTimer(entity);
                substateTimer.SetSeconds(1f);
                entity.PlaySound(VanillaSoundID.chestOpen);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_READY:
                        if (timer.Expired)
                        {
                            stateMachine.StartSubState(entity, SUBSTATE_SPIT);
                            timer.ResetSeconds(5f);
                        }
                        break;
                    case SUBSTATE_SPIT:
                        {
                            SpitProjectile(entity);
                            if (timer.Expired)
                            {
                                entity.PlaySound(VanillaSoundID.chestClose);
                                stateMachine.StartSubState(entity, SUBSTATE_END);
                            }
                        }
                        break;
                    case SUBSTATE_END:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            private void SpitProjectile(Entity entity)
            {
                entity.PlaySound(VanillaSoundID.bow);
                var rng = entity.RNG;
                var x = rng.NextFloat() * 10 + 10;
                var y = rng.NextFloat() * 10 + 10;
                var z = rng.NextFloat() * 5 - 2.5f;
                var velocity = new Vector3(x * entity.GetFacingX(), y, z);

                var param = entity.GetShootParams();
                param.projectileID = VanillaProjectileID.lockedChestTrash;
                param.velocity = velocity;
                param.damage = entity.GetDamage() * 0.2f;
                param.spawnParam.SetProperty(LogicEntityProps.VARIANT, LockedChestTrash.RandomVariant(rng));
                entity.ShootProjectile(param);
            }
            public const int SUBSTATE_READY = 0;
            public const int SUBSTATE_SPIT = 1;
            public const int SUBSTATE_END = 2;

            public const int ANIMATION_SUBSTATE_OPEN = 0;
            public const int ANIMATION_SUBSTATE_CLOSE = 1;
        }
        #endregion

        #region 吐僵尸蓝图
        private class SpitZombieBlueprintState : EntityStateMachineState
        {
            public SpitZombieBlueprintState() : base(STATE_SPIT_ZOMBIE_BLUEPRINTS, ANIMATION_STATE_OPEN_CHEST) { }
            public override int GetAnimationSubstate(int substate)
            {
                if (substate == SUBSTATE_END)
                {
                    return ANIMATION_SUBSTATE_CLOSE;
                }
                return ANIMATION_SUBSTATE_OPEN;
            }
            public override void OnEnter(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnEnter(stateMachine, entity);
                var substateTimer = stateMachine.GetSubStateTimer(entity);
                substateTimer.SetSeconds(1f);
                entity.PlaySound(VanillaSoundID.chestOpen);
            }
            public override void OnUpdateAI(EntityStateMachine stateMachine, Entity entity)
            {
                base.OnUpdateAI(stateMachine, entity);
                var substate = stateMachine.GetSubState(entity);
                var timer = stateMachine.GetSubStateTimer(entity);
                timer.Run(stateMachine.GetSpeed(entity));
                switch (substate)
                {
                    case SUBSTATE_READY:
                        if (timer.Expired)
                        {
                            stateMachine.StartSubState(entity, SUBSTATE_SPIT);
                            timer.ResetSeconds(1f);
                        }
                        break;
                    case SUBSTATE_SPIT:
                        {
                            SpitBlueprint(entity);
                            if (timer.Expired)
                            {
                                entity.PlaySound(VanillaSoundID.chestClose);
                                stateMachine.StartSubState(entity, SUBSTATE_END);
                            }
                        }
                        break;
                    case SUBSTATE_END:
                        if (timer.Expired)
                        {
                            stateMachine.StartState(entity, STATE_IDLE);
                        }
                        break;
                }
            }
            private void SpitBlueprint(Entity entity)
            {
                entity.PlaySound(VanillaSoundID.bow);
                var rng = entity.RNG;
                var x = rng.NextFloat() * 20 - 10;
                var y = rng.NextFloat() * 10 + 10;
                var z = rng.NextFloat() * 20 - 10;
                var velocity = new Vector3(x * entity.GetFacingX(), y, z);

                var blueprintID = entity.Level.GetLockedChestSpitBlueprintID();
                var shotPosition = entity.Position + entity.GetShotOffset();
                var param = entity.GetSpawnParams();
                param.SetProperty(VanillaPickupProps.CONTENT_ID, blueprintID);
                entity.Spawn(VanillaPickupID.blueprintPickup, shotPosition, param)?.Let(b =>
                {
                    b.Velocity = velocity;
                });
            }
            public const int SUBSTATE_READY = 0;
            public const int SUBSTATE_SPIT = 1;
            public const int SUBSTATE_END = 2;

            public const int ANIMATION_SUBSTATE_OPEN = 0;
            public const int ANIMATION_SUBSTATE_CLOSE = 1;
        }
